def findPathExists(root,u,v): 

    queue = collections.deque([root]);  
    seen = {root};  

    while queue: 

        curr =queue.popleft();  
        children =curr.children;  

        if curr==u: 
            break ;  

        elif curr==v:  
            return True;  

        for child in children:    

            if child not in seen:  
                seen.add(child); 
                queue.append(child);  

    return False;

