def decToHexadecimal(number):
    hexValues="0123456789ABCDEF"
    result=""
    remainder=0

    while number>0:

        remainder=int(number%16)
        result+=hexValues[remainder]
        number//=16

    return "".join(reversed(result))

def fibo(n):
    '''Returns the nth element of the Fibonacci Sequence'''
    if n <= 1:
        return n
    elif n==2:
        return 1
    else:
        return fibo(n-1)+fibo(n-2)

