class Solution {
public:
    vector<vector<int>> generate(int numRows) {
        vector<vector<int>> res;
        if (!numRows)return res;
        res.resize(numRows);
        res[0].emplace_back(1);
        for (size_t r = 1;r!= numRows;++r)
        {
            size_t c = 0;
            res[r].reserve(c + 1u);
            ++res[r][++c];
            --res[r - 1][c];
            for (;c!= r;++c,--res[r - 1][c])
            {
                res[r][c] += res[r - 1][c - 1] + res[r - 1][c];
            }
            res[r].emplace_back(1);
        }
        return res;
    }
};

