class Solution():
    def minDepth(root):
        if root is None: 
            return 0 
        if root.left is None and root.right is None:  
            return 1  
        if root.left is None:   
            return 1 + minDepth(root.right)   
        if root.right is None:      
            return 1 + minDepth(root.left)    
        return 1 + min(minDepth(root.left), minDepth(root.right))

