# Function returns True if num is Palindrome otherwise False
def checkPalindromeNumber(num):

    # Converting Number to String 
    strNum = str(num); 

    lengthOfStrNum = len(strNum)

    # If Length Of String Is Even Then Check From Middle Character To End And Reverse Word Else Do Not Change
    if((lengthOfStrNum % 2)==0): 
        startPoint = ((math.floor(lengthOfStrNum / 2)) - 1)
        endPoint   = (((math.ceil(lengthOfStrNum / 2))) * (-1))

        reversedWord = ""

        for charIndex in range(startPoint,endPoint ):

            reversedWord += strNum[charIndex];

        if(reversedWord==strNum):

            return "True"
        else:
            return "False";
    elif(((lengthOfStrNum%2)!=0)&(lengthOfStrNum!=1)): 

        middleCharPosition = math.floor(lengthOfStrNum / 2)

        reversedWord=""

        for charIndex in range(middleCharPosition,(lengthOfStrNum)-1):

            reversedWord += strNum[charIndex];

        reversedWord += strNum[(lengthOfStrNum)-1]

        if(reversedWord==strNum):

            return "True"
        else:
            return "False";
    else:
        return "True"



