class Solution:
    def coinChange(self, coins: List[int], amount: int) -> int:
        dp=[amount+1]*(amount+1) 
        dp[0]=0
        for j in range(1,amount+1):
            minCoins=dp[-j]
            for k in coins:
                if j>=k:
                    minCoins=min(minCoins,dp[j-k]+1)

            dp[j]=minCoins

        return dp[amount]==amount+1 and -1 or dp[amount]

