def fibonacciSequenceGenerator(number):

  if number == 0:
      yield 0

  elif number <= 2:
      yield 1

  else:

      previousNumber = 1

      currentNumber = 1

      for counter in range(2, number):
          nextNumber = previousNumber + currentNumber

          previousNumber = currentNumber

          currentNumber = nextNumber

          yield currentNumber

