    maxLength = float('-inf')
    subString=''

    for i in range(len(string)):

        tempSubStr = ''

        j = i 
        currLength = 0

        while j < min([len(string),i+l]):

            tempSubStr+=string[j]

            if len(tempSubStr)==min([len(string),i+l]-i):
                currLength = len(tempSubStr)

            elif len(tempSubStr)<min([len(string),i+l]-i):

                if len(subString)!=maxLength:
                    subString = tempSubStr

                currLength = len(tempSubStr)

            if currLength>=max([k,currLength-l]):
                maxLength = currLength 
                subString = tempSubStr

            j+=1

