class Stack{
    private final int[] arr;
    public int top=-1;//top points to last element inserted
    public Stack(final int capacity){//constructor
        this.arr=new int[capacity];
    }//end constructor
    public boolean isEmpty(){
        return top==-1?true:false;
    }//end isEmpty
    public int size(){
        return top+1;
    }//end size
    public void push(final int item){
        System.out.println("\nPushed "+item+" onto stack");
        try{
            Thread.sleep(10);//for better visualization purpose
        }catch(InterruptedException e){}
        ++this.top;
        this.arr[this.top]=item;
    }//end push
    public int pop(){
        --this.top;
        System.out.println("\nPopped out "+this.arr[this.top+1]);
        return this.arr[this.top+1];
    }//end pop
    public int peek(){
        return this.arr[this.top];
    }//end peek
    @Override
    public String toString(){
        StringBuffer buffer=new StringBuffer("[ ");
        for(int i=0;i<=this.top;++i){
            buffer.append(this.arr[i]).append(", ");
        }buffer.deleteCharAt(buffer.length()-1);
        buffer.deleteCharAt(buffer.length()-1);
        buffer.append(" ]").insert(0,"Size="+this.size()).insert(0,"\nTop="+(this.peek()==null?"Empty":this.peek()));
        return buffer.toString();
    }//end toString
    public void clearStack(){
        Arrays.fill(this.arr,-999);
        this.top=-1;
    }//end clearStack
}//end class

