class Solution:
    """
    @param root: The root of binary tree.
    @return: True if this Binary tree is Balanced otherwise return False
    """

    def isBalanced(self, root):
        # write your code here
        if root==None:
            return True

        lh=rh=-1
        hdiff=abs(lh - rh) > 1

        if abs(lh)>abs(rh)+1:
            hdiff=False

        elif abs(rh)>abs(lh+1):
            hdiff=False


        else:
            hdiff=self.isBalanced(root.left)==hdiff and \
                self.isBalanced(root.right)==hdiff

        return hdiff

class StackUsingArray {

    final int MAXSIZE = 100;
    int topOfStack=-1;//top of stack pointer
    int []stackArr={};//actual stack array

    /* Constructor */
    public StackUsingArray(){
       stackArr =new int[MAXSIZE];
   }

   /** Push element onto stack*/ 
   public void push(int value){ 
       if((topOfStack+1)<MAXSIZE)//check overflow condition
          stackArr[++topOfStack]=value;  
   }

   /** Pop element off stack*/ 
   public int pop(){ 
      if(!this.isEmpty()){ 
          return stackArr[topOfStack--];  
      }else{  
          throw new RuntimeException("Underflow Exception");  
      }  
   }

   /** Check whether stack is empty or not*/ 
   public Boolean isEmpty(){ 
      return ((topOfStack==(-1))?true:false);//return true when stack is empty 
   }
}

def myPow(x, n):
    ans = 1
    sign = True
    if n<0:
        sign = False
        n=-n
    while n>0:
        if n&1:
            ans*=x
        x *= x
        n>>=1
    if sign:
        return ans
    else:
        return 1./ans

