def multiplyWithoutMultiplyOperator(a,b):

  result=0

  # Iterate till b becomes zero  
  while b > 0:

    # If odd then add a with carry 
    if b % 2 == 1:
        result += a 

    # Addition of above step with previous summation 
    temp = ((result&a)<<1)+(result^a);  

    # Update a after adding its double to itself 
    a <<= 1;  

    # Bitwise AND operation 
    a &= ~(temp>>31);   

    # Right shift by one 
    b >>= 1; 

  print("Product of",a,"and",b,"is:",result )


