class Solution {
  public TreeNode pruneTree(TreeNode root) {
      // base case
      if(!root){
          return null;
      }

      // recursive call
      root.left=pruneTree(root.left);
      root.right=pruneTree(root.right);

      /* If both children of root are NULL then 
         root->data = 0 */
      if((!root.left &&!root.right)){
         return null;
      }

     /* Else return root which now may or may  
        not have its child */
      return root;
   }
}

