class MyStack: 
    q1 = deque([]) 

    # Push element x onto stack 
    def push(self,x): 
        self.q1.append(x) 

    # Removes the element on top of the stack 
    def pop(self): 
        size = len(self.q1) 

        while size > 1 : 
            temp = self.q1.popleft()  
            self.q1.append(temp)   
            size -= 1

        return self.q1.popleft() 

    # Get the top most element 
    def peek(self): 
        return self.q1[-1]

    # Return whether the stack is empty 
    def isEmpty(self): 
        return len(self.q1)==0

