def getMaxConsecutiveOnesCount(binaryNumberSequence):

    countOfMaxConsecutiveOnes = []  
    indexFirstOccurrence =[]   
    indexLastOccurrence =[]   

    for key,group in groupby(binaryNumberSequence):  
        tempGroup = ''.join(map(str,list(group)))   
        countOfMaxConsecutiveOnes += [(tempGroup.count('1'),key)] 

    try:    
        indexFirstOccurrence+=[(max(countOfMaxConsecutiveOnes))[1]]    
    except ValueError:     
        pass     

    try:       
        indexLastOccurrence+=[(min(countOfMaxConsecutiveOnes))[1]]      
    except ValueError:      
        pass       

    return f"{indexFirstOccurrence}\n{indexLastOccurrence}"  

