def getPairsSumToK(k, arr):

    result = []

    # Sort the Array so that smaller values are picked first
    sortedArr = sorted(set(arr))

    # Iterate through the array once again
    for numA in sortedArr:

        diffB = abs(numA - k)

        # Since B must always be greater 
        # than A, iterate only till halfway point  
        while diffB > ((len(sortedArr)-1)/2):  
            diffB -= len(sortedArr)

        # Now start iterating towards other end   
        indexB = int(diffB)

        # Find out all possible combinations between current number A & next number B
        comb = [(numA, val) 
                for idx,val in enumerate(sortedArr[(indexB+1):])]

        # Add them into our final results
        result.extend([(numA, val) 
                        for _,val in comb
                        ])

    return result


