def GCD(num_one, num_two):
    """Return the greatest common denominator between `num_one` and `num_two`."""

    # Base Case
    if num_one < num_two:
        temp = num_one
        num_one = num_two
        num_two = temp

    # Recursive case
    difference = abs(num_one - num_two)

    if difference!= 0:
        return GCD(difference, min(num_one, num_two))
    else:
        return num_one

def BubbleSort(arr):

    # Traverse through all array elements 
    for i in range(len(arr)):

        # Last i elements are already in place 
        for j in range(0, len(arr)-i-1):

            # traverse the array from 0 to n-i-1 
            # Swap if the element found is greater 
            # than the next element 
            if arr[j] > arr[j+1] : 
                arr[j], arr[j+1]=arr[j+1], arr[j] 

    return arr


