class ListNode:
      def __init__(self, val=0, next=None):
          self.val = val
          self.next = next
  class Solution:
      def reverseIterative(headNode : 'ListNode'):
          prev_node = headNode 
          curr_node = headNode.next

          while curr_node!= None:
              tempNext = curr_node.next 
              curr_node.next = prev_node

              prev_node = curr_node
              curr_node = tempNext

          headNode.next = None
          newHeadNode = prev_node

          return newHeadNode

      def reverseRecursiveHelper(curr_node,prev_node ):
          if curr_node==None:
              return prev_node 

          else:
              tempNext = curr_node.next

              curr_node.next = prev_node
              prev_node = curr_node
              curr_node = tempNext


              return reverseRecursiveHelper(tempNext,prev_node )


      def reverseRecursive(headNode:'ListNode' )->'ListNode':
          return reverseRecursiveHelper(headNode,None)

