    # If length of both strings is different then they 
    # cannot be permutations
    if len(str1)!=len(str2): 
        return False

    # Count frequency of all characters from first string
    freq = {} 

    for ch in str1 : 

        # Increment character count only when its found  
        # for the second time
        if ((ch in freq )!= -1 ): 
            freq[ch]+=1

        elif((ch in freq)==-1):  
            freq[ch]=1

    print ("Frequency array after processing first string ",freq); 

    # Now process the second string similarly  
    for ch in str2 :  

        if ((ch in freq )!= -1 ): 
            freq[ch]-=1

        elif((ch in freq)==-1):   
            freq[ch]=(-1)*1



    print ("Frequency array after processing second string ",freq); 


    # Check whether frequencies match or not
    flag = 0
    for key in freq : 

        if (((key in freq))and(abs(freq[key])!=0)): 

            flag+=1

    if (flag==0): 
