class Solution:
    def minAbsoluteSumDiff(self, nums: List[int], goal: int) -> int:

        diff = float('inf')
        sortedNums = sorted([x for x in nums])
        prevNum = None
        currSum = 0
        for index, currentNumber in enumerate(sortedNums):

            if previousIndex := index - 1:

                nextPreviousNumber = sortedNums[previousIndex]

                currDifference = math.fabs(currentNumber - nextPreviousNumber)

                if currDifference < diff:

                    diff = currDifference

                    newGoal = goal - currSum + currentNumber

                elif currDifference == diff:

                    newGoal = min(newGoal,goal - currSum + currentNumber)

            currSum += currentNumber

        return diff

