class Solution {
  public boolean isValid(String str){
      Stack<Character> stack=new Stack<>();

      char ch;

      // Push every character onto the stack 
      for(int i=0;i<str.length();++i){
          ch=str.charAt(i);

          switch(ch){
              case '}':
                  if(!stack.isEmpty()){
                    Character topElement=stack.peek();

                    if(topElement=='{' || topElement=='}'){
                        stack.pop();
                    }else{
                        return false;
                    }
                }else{
                    return false;
                }

                break;

              case ']':

                  if (!stack.isEmpty()) {

                      Character topElement = stack.peek();

                      if ((topElement == '[') ||
                          (topElement == ']')) {

                          stack.pop();

                      } else {

                          return false;

                      }

                  } else {

                      return false;

                  }

                  break;


              default:
                  stack.push(ch);
                  break;
          }


      }

      /* If the size of the
       * stack is zero then 
       * only then is the expression 
       * balanced */
      return stack.size()==0?true:false;

  }

}

public class QueueStack {
    LinkedList<Integer> queue1 = null; 
    LinkedList<Integer> queue2 = null; 

    /** Initialize your data structure here. */
    public QueueStack() {
        queue1 = new LinkedList<>();
        queue2 = new LinkedList<>();
    }

    /** Push element x onto stack. */
    public void push(int x) {

        /* First put everything back to original queue*/
        while(!queue1.isEmpty()){ 
            queue2.offerFirst(queue1.pollLast());

        } 

        /* Now insert item in between both queues */
        queue1.offerLast(x);

        /* Putting items back again */
        while(!queue2.isEmpty()){

            queue1.offerLast(queue2.pollFirst());

        }


    }

    /** Removes the element on top of the stack and returns that element. */
    public int pop() {
        return queue1.removeLast();
    }

    /** Get the top element. */
    public int peek() {
        return queue1.peekLast();
    }

    /** Returns whether the stack is empty. */
    public boolean isEmpty() {
        return queue1.size()==0?true:false;
    }
}

