def lcs(X, Y ): 

    LCSuff = [[0 for i in range(len(Y))]for j in range(len(X))] 


    ''' Following steps build L[m+1][n+1] in bottom up fashion. Note 
    that L[i][j] contains length of LCS of X[0..i-1] & Y[0..j-1]'''
    for i in range(m+1): 
        for j in range(n+1): 

            # If either string is empty then L[i][j]=0 
            if i == 0 or j == 0 : 
                LCSuff[i][j] = 0

            elif X[i-1] == Y[j-1]: 
                LCSuff[i][j] = LCSuff[i-1][j-1]+1

            else: 
                LCSuff[i][j] = max(LCSuff[i-1][j], LCSuff[i][j-1]) 


    '''Following code is needed only when LCSuff[][] is filled in above step */
