def getMaxLengthOfKDistinctCharactersSubstring(s,k ):

    # Initialize result
    maxLength = -float('inf')

    # Traverse through all substrings starting 
    # index from 0 till n-1
    for i in range(len(s)):

        # Dictionary to store frequencies 
        freqMap = {}

        j = i;

        # Count frequency of every character upto K
        while len(freqMap)<k and j<len(s):

            char = s[j]

            if char!= '?':
                freqMap[char]+=1

            j+=1

        # If count becomes equal to K then update answer
        if len(freqMap)==k:
            maxLength = max(maxLength,(j-i))

    return int(maxLength)

