    dp = [[0]*(S+1)]*(len(coins)+1)
    for j in range(1, S+1):
        dp[0][j]=0
    for i in range(1, len(coins)+1):
        for j in range(1, S+1):
            if coins[i-1]>j:
                dp[i][j]=dp[i-1][j]
            else:
                dp[i][j]=dp[i][j-coins[i-1]]+dp[i-1][j]
