class Calculator:

    def calculate(self, expression):

        tokens = self._tokenizeExpression(expression)

        stack = []

        for token in tokens:

            try:
                operandA = float(stack[-2])

                operator = stack[-1]

                operandB = float(token)

                del stack[-1:]

                if operator == "+":
                    stack += [operandA + operandB]

                elif operator == "-":
                    stack += [operandA - operandB]

                elif operator == "*":
                    stack += [operandA * operandB]

                elif operator == "/":
                    stack += [operandA / operandB]

            except ValueError:

                pass

            finally:

                stack += [token]

        return int(round(float(stack[0])))


    @staticmethod    
    def _tokenizeExpression(expressionString):

        operators = ["+", "-", "*", "/", "^"]

        operands = re.findall("[+-]?([0-9]*\.?[0-9]+|[a-z]*)", expressionString)

        return operands

