class Solution:
    def plusOne(self, digits: List[int]) -> List[int]:
        carry = True 
        lenghth = len(digits)-1
        while carry == True: 
            if lenghth < 0:  
                digits.insert(lenghth+1, 1 )   
                carry = False  
            elif digits[lenghth]!=9:  
                digits[lenghth] += 1  
                carry = False   
            else:  
                digits[lenghth] = 0  
                lenghth -= 1   
        return digits

