    def fiboWordSumSquare(l): 
        if l<=1: 
            return pow((pow(fiboWordSumSquare(l+1),2)),2) % m  
        elif l>1:  
            return ((pow(((fiboWordSumSquare(l)-1)*fiboWordSumSquare(l-1)),2))+pow((((fiboWordSumSquare(l)-1)*(fiboWordSumSquare(l-1))),2))) % m  

    return fiboWordSumSquare(1)  



