	}// end constructor


	/* Method to add Dog / Cat object 
	 * @param obj Object to be added
	 */	
	public boolean enqueue(Object obj){

		boolean status = false;

		try{
			Animal animalObj = null;

			switch ((Class<?>)obj.getClass()) {
			 case Dog.class:

			    animalObj = new Dog(((Dog)obj).getName());
			    break;

			  default:
				  System.err.println("Invalid Class");
			      throw new Exception();

			}

			status = true;

		}catch(Exception e){}


		return status;
	}// end method


	/**
	 * This method removes the oldest entry from the queue based upon priority
	 * @throws NoSuchElementException when there's no more elements left inside the queue
	 */
	@SuppressWarnings("unchecked")
	public Object dequeueAny() throws NoSuchElementException{

		Object obj = null;

		try{

			obj = this.queue.remove();

		} catch(NoSuchElementException ex){
			System.err.println("No More Elements Left Inside Queue!");
			throw ex;
		}

		return obj;
	}// end method


	/**
	 * This method removes the oldest entry from the queue based upon preference
	 * @param pref Preference to remove objects by
	 * @throws NoSuchElementException when there's no more elements left inside the queue
	 */
	@SuppressWarnings("unchecked")
	public Object dequeuePref(String pref) throws NoSuchElementException{

		Object obj = null;

		try{

			Iterator<?> iterator = this.queue.iterator();

			while(iterator.hasNext()){

				Object tmp = iterator.next();

				switch ((Class<?>)tmp.getClass()) {

					case Dog.class:

						if (((Dog)tmp).getPreference().equals(pref)){

							obj = tmp;
					        iterator.remove();

					    	break;
					    }

				    default:
				    	continue;

				}

			}

		} catch(NoSuchElementException ex){
			System.err.println("No More Elements Left Inside Queue!");
			throw ex;
		}

		return obj;		
	}// end method	

}// end class

